// Script Continued Below

function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'publish_tasks') {
		if (g_scratchpad.currentState != -6) {
			return false;
		}
		// STRY0154923
		checkForChildrenAndPublishIfNone();
		return false;
    }
}

// STRY0154923 - removing an update of parent task in the after update caused the calculated 
function checkForChildrenAndPublishIfNone(){
		var checkOrPublish = new GlideAjax("ClientTaskInfo");
		checkOrPublish.addParam('sysparm_name', 'taskCheckForChildrenAndPublish');
		checkOrPublish.addParam('syparm_taskId', g_form.getUniqueValue());
		checkOrPublish.getXML(checkCountAndPrompt);
}

function checkCountAndPrompt(response){
	var numberOfChildren = parseInt(response.responseXML.documentElement.getAttribute("answer"));
	if (numberOfChildren == 0) {
		// this should have already been processed on the server
	} else {
        var task_id = g_form.getUniqueValue();
        _requestParameters(task_id, "publish_tasks", confirmPublishTask);
        // asynchronous above will be processed in the modal, return false to prevent post back to publish
	}		
}

function confirmPublishTask(response) {
	var params = {};
	var sParams = response.responseXML.documentElement.getAttribute("answer");
	params = JSON.parse(sParams);

	var _spModal;
	if(typeof spModal != 'undefined'){
		_spModal = spModal;
	}
	var _spUtil;
	if(typeof spUtil != 'undefined'){
		_spUtil = spUtil;
	}

	if(x_153465_discovert.DTech_Task_Actions==undefined){
		ScriptLoader.getScripts(['x_153465_discovert.DTech_Task_Actions.jsdbx'], function() {
			x_153465_discovert.DTech_Task_Actions.confirmPublishDraftTasks(_spModal, _spUtil, g_form, params);
		});
	} else {
		// already loaded, just call it
		x_153465_discovert.DTech_Task_Actions.confirmPublishDraftTasks(_spModal, _spUtil, g_form, params);
	}
}

// NOTE: this might be able to be moved into the UI Script if the UI Script has access to GlideAjax
function _requestParameters(task_id, action_name, callback){
	var ajax  = new GlideAjax('ClientTaskInfo');
	ajax.addParam('sysparm_name', 'getTaskUIActionParamaters');
	ajax.addParam('sysparm_task_id', task_id);
	ajax.addParam('sysparm_action_name', action_name);
	ajax.getXML(callback);
}
